import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { forkJoin, of, switchMap } from 'rxjs';
import { catchError } from 'rxjs/operators';
import { ResumeAnalysis } from '../../core/models/analysis.model';
import { JobMatch } from '../../core/models/job.model';
import { GeneratedResume, ResumeResponse, ResumeTemplate, UsageLimit } from '../../core/models/resume.model';
import { User } from '../../core/models/user.model';
import { AuthService } from '../../core/services/auth.service';
import { JobService } from '../../core/services/job.service';
import { ResumeBuilderLocalService } from '../../core/services/resume-builder-local.service';
import { ResumeService } from '../../core/services/resume.service';

@Component({
  selector: 'app-dashboard',
  templateUrl: './dashboard.component.html'
})
export class DashboardComponent implements OnInit {
  readonly dashboardTemplateNames = ['ATS Internship', 'Fresher Software Developer', 'Professional One Page'];
  loading = true;
  guestMode = false;
  user: User | null = null;
  resumes: ResumeResponse[] = [];
  generatedResumes: GeneratedResume[] = [];
  publicTemplates: ResumeTemplate[] = [];
  latestResume: ResumeResponse | null = null;
  latestAnalysis: ResumeAnalysis | null = null;
  latestMatches: JobMatch[] = [];
  usageLimit: UsageLimit | null = null;
  readonly landingNavItems = ['Resume Templates', 'Pricing', 'About'];

  constructor(
    private readonly authService: AuthService,
    private readonly resumeService: ResumeService,
    private readonly jobService: JobService,
    private readonly resumeBuilderLocalService: ResumeBuilderLocalService,
    private readonly router: Router
  ) {
  }

  ngOnInit(): void {
    if (!this.authService.isAuthenticated()) {
      this.guestMode = true;
      this.generatedResumes = this.resumeBuilderLocalService.getResumes();
      this.resumeService.getTemplates().subscribe({
        next: (templates) => {
          this.publicTemplates = templates;
          this.loading = false;
        },
        error: () => {
          this.loading = false;
        }
      });
      return;
    }
    this.loadDashboard();
  }

  get recommendedTemplates(): ResumeTemplate[] {
    return this.dashboardTemplateNames
      .map((name) => this.publicTemplates.find((template) => template.name === name))
      .filter((template): template is ResumeTemplate => !!template);
  }

  get isPremiumUser(): boolean {
    return !!this.usageLimit?.premium;
  }

  get recentGeneratedResumes(): GeneratedResume[] {
    return this.generatedResumes.slice(0, 3);
  }

  get latestGeneratedResume(): GeneratedResume | null {
    return this.generatedResumes[0] ?? null;
  }

  get latestAnalysisRoute(): string[] {
    if (this.latestResume) {
      return ['/resume', String(this.latestResume.id), 'analysis'];
    }
    return ['/resume/upload'];
  }

  get dashboardScore(): number {
    return this.latestAnalysis?.atsScore ?? 0;
  }

  get scoreStatus(): string {
    return this.dashboardScore >= 75 ? 'Good' : 'Needs improvement';
  }

  get completionChecklist(): Array<{ label: string; done: boolean }> {
    const payload = this.latestGeneratedResume?.resumeDataJson?.toLowerCase() ?? '';
    return [
      { label: 'Summary added', done: payload.includes('summary') || payload.includes('headline') },
      { label: 'Experience added', done: payload.includes('experience') },
      { label: 'Skills added', done: payload.includes('skills') },
      { label: 'Education added', done: payload.includes('education') },
      { label: 'Projects added', done: payload.includes('projects') },
      { label: 'Certifications added', done: payload.includes('certifications') }
    ];
  }

  logout(): void {
    this.authService.logout();
    void this.router.navigate(['/']);
  }

  templateUseRoute(template: ResumeTemplate): string[] {
    if (template.premium && !this.isPremiumUser) {
      return ['/pricing'];
    }
    return ['/resume-builder/create', String(template.id)];
  }

  editorRoute(resumeId: number): string[] {
    return ['/resume-builder/edit', String(resumeId)];
  }

  changeTemplateRoute(resumeId: number): string[] {
    return ['/resume-editor', String(resumeId), 'change-template'];
  }

  private loadDashboard(): void {
    this.loading = true;
    this.authService.getProfile().pipe(
      switchMap((user) => {
        this.user = user;
        return forkJoin({
          resumes: this.resumeService.getResumes(),
          generatedResumes: this.resumeService.getGeneratedResumes().pipe(catchError(() => of([]))),
          usageLimit: this.resumeService.getUsageLimit().pipe(catchError(() => of(null))),
          templates: this.resumeService.getTemplates().pipe(catchError(() => of([])))
        });
      }),
      switchMap(({ resumes, generatedResumes, usageLimit, templates }) => {
        this.resumes = resumes;
        this.generatedResumes = generatedResumes;
        this.usageLimit = usageLimit;
        this.publicTemplates = templates;
        this.latestResume = resumes[0] ?? null;

        if (!this.latestResume) {
          return of({ analysis: null, matches: [] as JobMatch[] });
        }

        return forkJoin({
          analysis: this.resumeService.getResumeAnalysis(this.latestResume.id).pipe(
            catchError(() => of(null))
          ),
          matches: this.jobService.getJobMatches(this.latestResume.id).pipe(
            catchError(() => of([]))
          )
        });
      })
    ).subscribe({
      next: ({ analysis, matches }) => {
        this.latestAnalysis = analysis;
        this.latestMatches = matches;
        this.loading = false;
      },
      error: () => {
        this.loading = false;
      }
    });
  }
}
<app-loader *ngIf="loading" message="Loading your dashboard"></app-loader>

<div *ngIf="!loading && guestMode" class="app-shell px-5 py-5 md:px-8 lg:px-10">
  <div class="mx-auto max-w-[1360px]">
    <header class="shell-card px-6 py-5 md:px-8">
      <div class="flex flex-wrap items-center justify-between gap-6">
        <div class="flex items-center gap-3">
          <div class="flex h-12 w-12 items-center justify-center rounded-2xl bg-gradient-to-br from-[#5b5cf0] to-[#7c4dff] text-sm font-extrabold text-white">R</div>
          <div>
            <p class="text-base font-extrabold text-[#17172b]">ResumeAI</p>
            <p class="text-sm text-[#7a81ad]">Build resumes that clear ATS and hiring screens</p>
          </div>
        </div>

        <nav class="hidden items-center gap-10 text-sm font-semibold text-[#6f76a3] lg:flex">
          <a *ngFor="let item of landingNavItems" href="#" class="transition hover:text-[#17172b]">{{ item }}</a>
        </nav>

        <div class="flex items-center gap-3">
          <a routerLink="/auth/login" class="btn-secondary">Login</a>
          <a routerLink="/auth/register" class="btn-primary">Get Started</a>
        </div>
      </div>
    </header>

    <section class="grid items-center gap-10 py-10 lg:grid-cols-[0.92fr_1.08fr] lg:py-14">
      <div class="max-w-[620px]">
        <span class="tag-chip">AI Powered Resume Workspace</span>
        <h1 class="section-title mt-6 text-5xl leading-[0.95] text-[#17172b] md:text-7xl">
          Resumes that get noticed before your interview starts.
        </h1>
        <p class="mt-6 max-w-[560px] text-lg leading-8 text-[#667085]">
          Upload an existing resume, build a fresh one from a template, score it for ATS, and find stronger job matches without bouncing between tools.
        </p>

        <div class="mt-8 grid gap-3 text-sm text-[#4f567d]">
          <div class="flex items-center gap-3 rounded-2xl bg-white/70 px-4 py-3">
            <span class="h-2.5 w-2.5 rounded-full bg-[#5b5cf0]"></span>
            ATS-friendly templates for faster shortlisting
          </div>
          <div class="flex items-center gap-3 rounded-2xl bg-white/70 px-4 py-3">
            <span class="h-2.5 w-2.5 rounded-full bg-[#22c55e]"></span>
            Resume scoring with actionable content feedback
          </div>
          <div class="flex items-center gap-3 rounded-2xl bg-white/70 px-4 py-3">
            <span class="h-2.5 w-2.5 rounded-full bg-[#f59e0b]"></span>
            Matching roles based on real skill gaps
          </div>
        </div>

        <div class="mt-8 flex flex-wrap gap-4">
          <a routerLink="/templates" class="btn-primary px-7">Create My Resume</a>
          <a routerLink="/resume/upload" class="btn-secondary px-7">Upload Resume</a>
        </div>

        <div class="mt-10 grid gap-4 md:grid-cols-2" *ngIf="generatedResumes.length > 0">
          <article *ngFor="let item of generatedResumes | slice:0:2" class="shell-card p-5">
            <p class="eyebrow">{{ item.templateName }}</p>
            <h3 class="mt-3 text-xl font-extrabold text-[#17172b]">{{ item.title }}</h3>
            <p class="mt-2 text-sm leading-6 text-[#667085]">Continue a saved draft from your previous builder session.</p>
            <div class="mt-5 flex gap-3">
              <a [routerLink]="['/resume-builder/preview', item.id]" class="btn-primary px-4 py-2 text-sm">Preview</a>
              <a [routerLink]="['/resume-builder/edit', item.id]" class="btn-secondary px-4 py-2 text-sm">Edit</a>
            </div>
          </article>
        </div>
      </div>

      <div class="relative">
        <div class="shell-card mx-auto max-w-[720px] overflow-hidden p-4">
          <div class="grid gap-4 rounded-[28px] bg-[#f8f9ff] p-4 lg:grid-cols-[0.34fr_0.66fr]">
            <aside class="rounded-[24px] bg-[#17172b] p-5 text-white">
              <div class="flex items-center gap-3">
                <div class="h-10 w-10 rounded-2xl bg-white/10"></div>
                <div>
                  <p class="text-sm font-bold">Rohan Sharma</p>
                  <p class="text-xs text-white/55">Software Developer</p>
                </div>
              </div>

              <div class="mt-6 space-y-3">
                <div class="rounded-2xl bg-[#5b5cf0] px-4 py-3 text-sm font-semibold">Personal Info</div>
                <div class="rounded-2xl bg-white/6 px-4 py-3 text-sm text-white/70">Education</div>
                <div class="rounded-2xl bg-white/6 px-4 py-3 text-sm text-white/70">Skills</div>
                <div class="rounded-2xl bg-white/6 px-4 py-3 text-sm text-white/70">Projects</div>
                <div class="rounded-2xl bg-white/6 px-4 py-3 text-sm text-white/70">Preview</div>
              </div>

              <div class="mt-6 rounded-[22px] bg-white/8 p-4">
                <p class="text-xs uppercase tracking-[0.26em] text-white/45">ATS Score</p>
                <p class="mt-3 text-4xl font-extrabold">82</p>
                <p class="mt-2 text-sm text-[#8bf0a7]">Good score</p>
              </div>
            </aside>

            <div class="grid gap-4">
              <div class="grid gap-4 md:grid-cols-4">
                <div class="metric-card">
                  <p class="text-sm text-[#7a81ad]">Resumes</p>
                  <p class="mt-3 text-3xl font-extrabold text-[#17172b]">2</p>
                </div>
                <div class="metric-card">
                  <p class="text-sm text-[#7a81ad]">ATS Score</p>
                  <p class="mt-3 text-3xl font-extrabold text-[#17172b]">82</p>
                </div>
                <div class="metric-card">
                  <p class="text-sm text-[#7a81ad]">Job Matches</p>
                  <p class="mt-3 text-3xl font-extrabold text-[#17172b]">12</p>
                </div>
                <div class="metric-card">
                  <p class="text-sm text-[#7a81ad]">Applications</p>
                  <p class="mt-3 text-3xl font-extrabold text-[#17172b]">5</p>
                </div>
              </div>

              <div class="grid gap-4 md:grid-cols-[0.58fr_0.42fr]">
                <div class="shell-card p-5">
                  <div class="flex items-center justify-between">
                    <div>
                      <p class="eyebrow">Recent Activity</p>
                      <h3 class="mt-2 text-xl font-extrabold text-[#17172b]">Builder progress</h3>
                    </div>
                    <span class="tag-chip">Live</span>
                  </div>
                  <div class="mt-5 space-y-4 text-sm text-[#667085]">
                    <div class="flex items-center justify-between rounded-2xl bg-[#f8f9ff] px-4 py-3">
                      <span>Resume "Software Developer" updated</span>
                      <span>2h</span>
                    </div>
                    <div class="flex items-center justify-between rounded-2xl bg-[#f8f9ff] px-4 py-3">
                      <span>New ATS analysis generated</span>
                      <span>6h</span>
                    </div>
                    <div class="flex items-center justify-between rounded-2xl bg-[#f8f9ff] px-4 py-3">
                      <span>12 jobs matched to resume profile</span>
                      <span>1d</span>
                    </div>
                  </div>
                </div>

                <div class="shell-card p-5">
                  <p class="eyebrow">Improve Your Score</p>
                  <h3 class="mt-2 text-xl font-extrabold text-[#17172b]">Add stronger keywords</h3>
                  <p class="mt-4 text-sm leading-6 text-[#667085]">Match missing skills with clearer project outcomes and role-specific terms.</p>
                  <div class="mt-5 h-3 overflow-hidden rounded-full bg-[#eceeff]">
                    <div class="h-full w-[82%] rounded-full bg-gradient-to-r from-[#5b5cf0] to-[#7c4dff]"></div>
                  </div>
                  <p class="mt-3 text-sm font-semibold text-[#17172b]">82 / 100</p>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div class="absolute -bottom-4 left-4 hidden rounded-[24px] bg-white px-5 py-4 shadow-[0_18px_40px_rgba(67,72,121,0.12)] lg:block">
          <p class="text-sm font-semibold text-[#17172b]">Trusted by early job seekers</p>
          <p class="mt-2 text-sm text-[#667085]">Design aligned to guided resume and application flows.</p>
        </div>
      </div>
    </section>

    <section class="py-4">
      <div class="mb-6 flex flex-wrap items-end justify-between gap-4">
        <div>
          <p class="eyebrow">Recommended Templates</p>
          <h2 class="section-title mt-2 max-w-3xl text-4xl text-[#17172b] md:text-5xl">
            Pick from ATS-friendly templates
          </h2>
        </div>
        <a routerLink="/templates" class="btn-secondary">Browse all templates</a>
      </div>

      <div class="grid gap-5 md:grid-cols-3" *ngIf="recommendedTemplates.length > 0; else noTemplates">
        <article *ngFor="let template of recommendedTemplates" class="shell-card p-4">
          <div class="overflow-hidden rounded-[22px] bg-[#f8f9ff]">
            <img [src]="template.previewImageUrl" [alt]="template.name" class="h-[320px] w-full object-cover object-top">
          </div>
          <div class="px-1 pb-1 pt-4">
            <div class="flex items-center justify-between gap-3">
              <div>
                <p class="eyebrow">{{ template.category }}</p>
                <h3 class="mt-2 text-xl font-extrabold text-[#17172b]">{{ template.name }}</h3>
                <p class="mt-2 text-sm text-[#667085]">{{ template.category }} · {{ template.layoutType }} · ATS Friendly</p>
              </div>
              <span class="rounded-full px-3 py-1.5 text-xs font-bold"
                    [ngClass]="template.premium ? 'bg-[#fff0f0] text-[#ef4444]' : 'bg-[#ecfdf3] text-[#16a34a]'">
                {{ template.premium ? 'Premium' : 'Free' }}
              </span>
            </div>
            <div class="mt-5 flex gap-3">
              <a [routerLink]="['/templates', template.id, 'preview']" class="btn-secondary flex-1 text-sm">Preview</a>
              <a [routerLink]="templateUseRoute(template)" class="btn-primary flex-1 text-sm">Use template</a>
            </div>
          </div>
        </article>
      </div>

      <ng-template #noTemplates>
        <div class="shell-card p-8 text-center text-[#667085]">
          No templates available yet. Upload templates as admin to populate this section.
        </div>
      </ng-template>
    </section>
  </div>
</div>

<div *ngIf="!loading && !guestMode" class="space-y-5">
  <section class="shell-card p-5 md:p-6">
    <div class="flex flex-wrap items-center justify-between gap-4">
      <div>
        <p class="eyebrow">Candidate Dashboard</p>
        <h2 class="section-title mt-2 text-3xl text-[#17172b]">Sharper resumes. Faster applications.</h2>
      </div>
      <div class="flex items-center gap-3">
        <div class="rounded-2xl border border-[#dfe3f6] bg-[#f8f9ff] px-4 py-2 text-sm font-semibold text-[#17172b]">
          {{ user?.name || 'Candidate' }}
        </div>
        <button type="button" class="btn-secondary" (click)="logout()">Logout</button>
      </div>
    </div>
  </section>

  <section class="grid gap-5 xl:grid-cols-[1.45fr_1fr]">
    <div class="space-y-5">
      <article class="shell-card p-6">
        <h3 class="section-title text-3xl text-[#17172b]">Welcome back, {{ user?.name || 'Candidate' }}</h3>
        <p class="mt-3 text-sm leading-7 text-[#667085]">Create, improve, and manage your resumes in one place.</p>
        <div class="mt-5 flex flex-wrap gap-3">
          <a routerLink="/templates" class="btn-primary">Create Resume</a>
          <a routerLink="/resume/upload" class="btn-secondary">Upload Resume</a>
        </div>
      </article>

      <article class="shell-card p-6">
        <p class="eyebrow">Quick actions</p>
        <div class="mt-4 grid gap-3 sm:grid-cols-2">
          <a routerLink="/templates" class="soft-card p-4">
            <p class="font-semibold text-[#17172b]">Create New Resume</p>
            <p class="mt-1 text-sm text-[#667085]">Start with ATS-friendly templates.</p>
          </a>
          <a routerLink="/resume/upload" class="soft-card p-4">
            <p class="font-semibold text-[#17172b]">Upload Resume</p>
            <p class="mt-1 text-sm text-[#667085]">Get ATS analysis on existing PDF.</p>
          </a>
          <a routerLink="/templates" class="soft-card p-4">
            <p class="font-semibold text-[#17172b]">Browse Templates</p>
            <p class="mt-1 text-sm text-[#667085]">Explore layouts and roles.</p>
          </a>
          <a [routerLink]="latestAnalysisRoute" class="soft-card p-4">
            <p class="font-semibold text-[#17172b]">View Latest Analysis</p>
            <p class="mt-1 text-sm text-[#667085]">See score and improvement actions.</p>
          </a>
        </div>
      </article>

      <article class="shell-card p-6" *ngIf="recentGeneratedResumes.length > 0; else emptyResumes">
        <div class="flex items-center justify-between">
          <p class="eyebrow">Recent resumes</p>
          <a routerLink="/templates" class="text-sm font-semibold text-[#5b5cf0]">Create new</a>
        </div>
        <div class="mt-4 space-y-3">
          <div *ngFor="let item of recentGeneratedResumes" class="rounded-2xl border border-[#e5e7eb] p-4">
            <div class="flex flex-wrap items-start justify-between gap-3">
              <div>
                <p class="font-semibold text-[#17172b]">{{ item.title }}</p>
                <p class="text-sm text-[#667085]">{{ item.templateName }} • {{ item.updatedAt | date:'mediumDate' }}</p>
                <p class="mt-1 text-xs text-[#667085]">ATS score: {{ latestAnalysis?.atsScore ?? 'Pending' }}</p>
              </div>
              <div class="flex flex-wrap gap-2">
                <a [routerLink]="editorRoute(item.id)" class="btn-secondary px-3 py-2 text-xs">Edit</a>
                <a [routerLink]="changeTemplateRoute(item.id)" class="btn-secondary px-3 py-2 text-xs">Change Template</a>
                <a [routerLink]="['/resume-builder/preview', item.id]" class="btn-primary px-3 py-2 text-xs">Download</a>
              </div>
            </div>
          </div>
        </div>
      </article>
      <ng-template #emptyResumes>
        <article class="shell-card p-6">
          <h4 class="text-xl font-extrabold text-[#17172b]">No resumes yet</h4>
          <p class="mt-2 text-sm text-[#667085]">Start by creating your first ATS-friendly resume.</p>
          <div class="mt-4 flex flex-wrap gap-3">
            <a routerLink="/templates" class="btn-primary">Create Resume</a>
            <a routerLink="/templates" class="btn-secondary">Browse Templates</a>
          </div>
        </article>
      </ng-template>
    </div>

    <div class="space-y-5">
      <article class="shell-card p-6">
        <p class="eyebrow">ATS Score</p>
        <div class="mt-4 flex items-center gap-4">
          <div class="flex h-20 w-20 items-center justify-center rounded-full border-8 border-[#dbe4ff] text-2xl font-extrabold text-[#17172b]">{{ dashboardScore }}</div>
          <div>
            <p class="text-lg font-semibold text-[#17172b]">{{ scoreStatus }}</p>
            <a [routerLink]="latestAnalysisRoute" class="mt-2 inline-flex text-sm font-semibold text-[#5b5cf0]">Improve Score</a>
          </div>
        </div>
      </article>

      <article class="shell-card p-6">
        <p class="eyebrow">Resume Progress</p>
        <ul class="mt-4 space-y-2 text-sm">
          <li *ngFor="let item of completionChecklist" class="flex items-center justify-between rounded-xl bg-[#f8f9ff] px-3 py-2">
            <span>{{ item.label }}</span>
            <span class="font-semibold" [ngClass]="item.done ? 'text-[#16a34a]' : 'text-[#b45309]'">{{ item.done ? 'Done' : 'Pending' }}</span>
          </li>
        </ul>
      </article>

      <article class="shell-card p-6">
        <div class="flex items-center justify-between">
          <p class="eyebrow">Recommended Templates</p>
          <a routerLink="/templates" class="text-sm font-semibold text-[#5b5cf0]">Browse all templates</a>
        </div>
        <div class="mt-4 space-y-3" *ngIf="recommendedTemplates.length > 0; else noRecommendedTemplates">
          <div *ngFor="let template of recommendedTemplates | slice:0:3" class="flex items-center gap-3 rounded-2xl border border-[#e5e7eb] p-3">
            <img [src]="template.previewImageUrl" [alt]="template.name" class="h-14 w-12 rounded-lg object-cover object-top">
            <div class="min-w-0 flex-1">
              <p class="truncate text-sm font-semibold text-[#17172b]">{{ template.name }}</p>
              <p class="text-xs text-[#667085]">{{ template.layoutType }}</p>
            </div>
            <a [routerLink]="templateUseRoute(template)" class="btn-secondary px-3 py-2 text-xs">Use</a>
          </div>
        </div>
        <ng-template #noRecommendedTemplates>
          <p class="mt-4 text-sm text-[#667085]">Templates are not available yet. Browse full library when ready.</p>
        </ng-template>
      </article>

      <article class="shell-card p-6">
        <p class="eyebrow">Premium Upgrade</p>
        <ul class="mt-3 space-y-1 text-sm text-[#667085]">
          <li>• Unlock premium templates</li>
          <li>• Unlimited edits</li>
          <li>• AI suggestions</li>
          <li>• No watermark</li>
        </ul>
        <a routerLink="/pricing" class="btn-primary mt-4 inline-flex">Upgrade</a>
      </article>
    </div>
  </section>
</div>
